func expandChronicleDataTableColumnInfo(v interface{}, d tpgresource.TerraformResourceData, config *transport_tpg.Config) (interface{}, error) {
	if v == nil {
		return nil, nil
	}
	l := v.([]interface{})
	req := make([]interface{}, 0, len(l))
	for _, raw := range l {
		if raw == nil {
			continue
		}
		original := raw.(map[string]interface{})
		transformed := make(map[string]interface{})

		transformedColumnIndex, err := expandChronicleDataTableColumnInfoColumnIndex(original["column_index"], d, config)
		if err != nil {
			return nil, err
		} else if val := reflect.ValueOf(transformedColumnIndex); val.IsValid() && !tpgresource.IsEmptyValue(val) {
			transformed["columnIndex"] = transformedColumnIndex
		}

		transformedColumnType, err := expandChronicleDataTableColumnInfoColumnType(original["column_type"], d, config)
		if err != nil {
			return nil, err
		} else if val := reflect.ValueOf(transformedColumnType); val.IsValid() && !tpgresource.IsEmptyValue(val) {
			transformed["columnType"] = transformedColumnType
		}

		transformedKeyColumn, err := expandChronicleDataTableColumnInfoKeyColumn(original["key_column"], d, config)
		if err != nil {
			return nil, err
		} else if val := reflect.ValueOf(transformedKeyColumn); val.IsValid() && !tpgresource.IsEmptyValue(val) {
			transformed["keyColumn"] = transformedKeyColumn
		}

		transformedMappedColumnPath, err := expandChronicleDataTableColumnInfoMappedColumnPath(original["mapped_column_path"], d, config)
		if err != nil {
			return nil, err
		} else if val := reflect.ValueOf(transformedMappedColumnPath); val.IsValid() && !tpgresource.IsEmptyValue(val) {
			transformed["mappedColumnPath"] = transformedMappedColumnPath
		}

		transformedOriginalColumn, err := expandChronicleDataTableColumnInfoOriginalColumn(original["original_column"], d, config)
		if err != nil {
			return nil, err
		} else if val := reflect.ValueOf(transformedOriginalColumn); val.IsValid() && !tpgresource.IsEmptyValue(val) {
			transformed["originalColumn"] = transformedOriginalColumn
		}

		transformedRepeatedValues, err := expandChronicleDataTableColumnInfoRepeatedValues(original["repeated_values"], d, config)
		if err != nil {
			return nil, err
		} else if val := reflect.ValueOf(transformedRepeatedValues); val.IsValid() && !tpgresource.IsEmptyValue(val) {
			transformed["repeatedValues"] = transformedRepeatedValues
		}

		req = append(req, transformed)
	}
	return req, nil
}

